import{_ as e,o,c as s,a2 as i}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Creating Casino Pages","description":"Creating Casino Pages with Spinoko Theme","frontmatter":{"title":"Creating Casino Pages","description":"Creating Casino Pages with Spinoko Theme","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/creating-casino-pages"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/creating-casino-pages"}],["meta",{"property":"og:title","content":"Creating Casino Pages"}],["meta",{"property":"og:description","content":"Creating Casino Pages with Spinoko Theme"}],["meta",{"name":"twitter:title","content":"Creating Casino Pages"}],["meta",{"name":"twitter:description","content":"Creating Casino Pages with Spinoko Theme"}]]},"headers":[],"relativePath":"docs/spinoko/creating-casino-pages.md","filePath":"docs/spinoko/creating-casino-pages.md"}'),n={name:"docs/spinoko/creating-casino-pages.md"};function t(r,a,c,p,l,d){return o(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="creating-casino-pages" tabindex="-1">Creating Casino Pages <a class="header-anchor" href="#creating-casino-pages" aria-label="Permalink to &quot;Creating Casino Pages&quot;">​</a></h1><p>In your WordPress dashboard you will find a new menu item called <strong>Casinos</strong> right below the <strong>Pages</strong> menu link. Click <code>Add New</code> to add a new casino.</p><h3 id="casino-page-templates" tabindex="-1">Casino Page Templates <a class="header-anchor" href="#casino-page-templates" aria-label="Permalink to &quot;Casino Page Templates&quot;">​</a></h3><p>This page describes casino specific fields, for casino page templates, please follow this <a href="/docs/spinoko/casino-page-templates">link</a>.</p><h3 id="casino-fields" tabindex="-1">Casino Fields <a class="header-anchor" href="#casino-fields" aria-label="Permalink to &quot;Casino Fields&quot;">​</a></h3><p>Besides adding the casino title and content as usual, you&#39;ll find Casino Fields section below the page content. Here you can define properties for each casino.</p><p>Casino fields are in separate sections and have descriptions to make it easy for you to fill them in. These properties are used all over the website, please make sure to complete them.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-casino-fields.png" alt="Spinoko Casino Fields"></p><h3 id="casino-page-blocks" tabindex="-1">Casino Page Blocks <a class="header-anchor" href="#casino-page-blocks" aria-label="Permalink to &quot;Casino Page Blocks&quot;">​</a></h3><p>To present the information more visually you can use <a href="/docs/spinoko/casino-page-blocks">casino blocks</a> in casino page contents, as well as <a href="/docs/spinoko/blocks">generic blocks</a> such as FAQs, Recent posts, etc.</p><h3 id="casino-page-top-tables" tabindex="-1">Casino Page Top Tables <a class="header-anchor" href="#casino-page-top-tables" aria-label="Permalink to &quot;Casino Page Top Tables&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-casino-info-pros-cons.png" alt="spinoko-casino-top-tables"></p><p>By default on all casino pages, after the hero section appear 3 small tables: Info, Pros &amp; Cons. These are generated from Casino Fields as well and you can disable them globally for your website in <strong>Appearance</strong> → <strong>Customize</strong> → <a href="/docs/spinoko/customizations#review-options">Review Options</a>.</p><h3 id="casino-categories-and-tags" tabindex="-1">Casino Categories and Tags <a class="header-anchor" href="#casino-categories-and-tags" aria-label="Permalink to &quot;Casino Categories and Tags&quot;">​</a></h3><p><code>💁 since version 2.3.1</code></p><p>You can assign casino categories and tags to casinos. You do that the same way you&#39;d do it for regular posts. You can also manage your casino categories and casino tags by visiting their corresponding pages under &quot;Casinos&quot; menu item.</p>',16)])])}const m=e(n,[["render",t]]);export{h as __pageData,m as default};
